arguments.file_text:
@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <nav class="settings-sidebar">
        <h3 class="sidebar-title">Settings</h3>
        <ul class="sidebar-nav">
            @foreach (var section in _sections)
            {
                <li class="@(section.Key == _activeSection ? "active" : "")"
                    @onclick="() => SetActiveSection(section.Key)">
                    <span class="nav-icon">@section.Icon</span>
                    <span>@section.Label</span>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "👤"),
        new("notifications", "Notifications", "🔔"),
        new("security", "Security", "🔒"),
        new("appearance", "Appearance", "🎨"),
    ];

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }
}

.settings-layout {
    display: flex;
    gap: 0;
    min-height: 80vh;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: #333;
    border-bottom: 1px solid #dee2e6;
}

.sidebar-nav {
    list-style: none;
    padding: 0.5rem 0;
    margin: 0;
}

.sidebar-nav li {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.7rem 1.25rem;
    cursor: pointer;
    color: #555;
    font-size: 0.95rem;
    transition: background 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-nav li:hover {
    background: #e9ecef;
    color: #333;
}

.sidebar-nav li.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

/* Shared section styles */
::deep .section-header {
    margin-bottom: 1.5rem;
    padding-bottom: 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

::deep .section-header h2 {
    margin: 0;
    font-size: 1.4rem;
    font-weight: 600;
}

::deep .section-header p {
    margin: 0.25rem 0 0;
    color: #6c757d;
    font-size: 0.9rem;
}

::deep .form-group {
    margin-bottom: 1rem;
}

::deep .form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.3rem;
    font-size: 0.9rem;
    color: #333;
}

::deep .form-group input[type="text"],
::deep .form-group input[type="email"],
::deep .form-group input[type="password"],
::deep .form-group textarea,
::deep .form-group select {
    width: 100%;
    max-width: 450px;
    padding: 0.45rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 6px;
    font-size: 0.95rem;
    transition: border-color 0.15s;
}

::deep .form-group input:focus,
::deep .form-group textarea:focus,
::deep .form-group select:focus {
    border-color: #86b7fe;
    outline: 0;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.15);
}

::deep .btn {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1.2rem;
    border: none;
    border-radius: 6px;
    font-size: 0.9rem;
    font-weight: 500;
    cursor: pointer;
    transition: background 0.15s, opacity 0.15s;
}

::deep .btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

::deep .btn-primary {
    background: #0d6efd;
    color: #fff;
}

::deep .btn-primary:hover:not(:disabled) {
    background: #0b5ed7;
}

::deep .btn-secondary {
    background: #6c757d;
    color: #fff;
}

::deep .btn-secondary:hover:not(:disabled) {
    background: #5c636a;
}

::deep .btn-danger {
    background: #dc3545;
    color: #fff;
}

::deep .btn-danger:hover:not(:disabled) {
    background: #bb2d3b;
}

::deep .btn-outline {
    background: transparent;
    border: 1px solid #ced4da;
    color: #333;
}

::deep .btn-outline:hover:not(:disabled) {
    background: #f8f9fa;
}

::deep .btn-sm {
    padding: 0.3rem 0.8rem;
    font-size: 0.82rem;
}

::deep .button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

::deep .toast-message {
    padding: 0.6rem 1rem;
    border-radius: 6px;
    font-size: 0.9rem;
    margin-bottom: 1rem;
    animation: toast-in 0.3s ease;
}

::deep .toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

::deep .toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

@keyframes toast-in {
    from { opacity: 0; transform: translateY(-8px); }
    to { opacity: 1; transform: translateY(0); }
}

::deep .toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    max-width: 450px;
    padding: 0.75rem 0;
    border-bottom: 1px solid #f0f0f0;
}

::deep .toggle-label {
    font-weight: 500;
    font-size: 0.95rem;
}

::deep .toggle-desc {
    font-size: 0.82rem;
    color: #6c757d;
}

::deep .switch {
    position: relative;
    width: 44px;
    height: 24px;
    flex-shrink: 0;
}

::deep .switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

::deep .slider {
    position: absolute;
    inset: 0;
    background: #ccc;
    border-radius: 24px;
    cursor: pointer;
    transition: background 0.2s;
}

::deep .slider::before {
    content: "";
    position: absolute;
    width: 18px;
    height: 18px;
    left: 3px;
    bottom: 3px;
    background: #fff;
    border-radius: 50%;
    transition: transform 0.2s;
}

::deep .switch input:checked + .slider {
    background: #0d6efd;
}

::deep .switch input:checked + .slider::before {
    transform: translateX(20px);
}

