@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Profile</h2>
    <p>Manage your personal information</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_loading)
{
    <p>Loading profile…</p>
}
else
{
    <div class="profile-layout">
        <div class="profile-form">
            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_email" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="form-group">
                <label for="avatarUrl">Avatar URL</label>
                <input id="avatarUrl" type="text" @bind="_avatarUrl" />
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save Changes")
                </button>
                <button class="btn btn-outline" @onclick="DiscardChanges">
                    Discard Changes
                </button>
            </div>
        </div>

        <div class="avatar-preview">
            <div class="avatar-frame">
                @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                {
                    <img src="@_avatarUrl" alt="Avatar preview" />
                }
                else
                {
                    <div class="avatar-placeholder">No Avatar</div>
                }
            </div>
            <span class="avatar-label">Avatar Preview</span>
        </div>
    </div>
}

@code {
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    private UserProfile? _savedProfile;
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _toastMessage = "Profile saved successfully!";
            _toastIsError = false;
        }
        catch (Exception)
        {
            _toastMessage = "Failed to save profile. Please try again.";
            _toastIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _toastMessage = null;
        }
    }
}

