arguments.file_text:
@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Notifications</h2>
    <p>Control how you receive notifications</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message toast-success">@_toastMessage</div>
}

@if (_loading)
{
    <p>Loading notification preferences…</p>
}
else
{
    <div class="toggle-row">
        <div>
            <div class="toggle-label">Email Notifications</div>
            <div class="toggle-desc">Receive notifications via email</div>
        </div>
        <label class="switch">
            <input type="checkbox" @bind="_emailNotifications" />
            <span class="slider"></span>
        </label>
    </div>

    <div class="toggle-row">
        <div>
            <div class="toggle-label">Push Notifications</div>
            <div class="toggle-desc">Receive push notifications in browser</div>
        </div>
        <label class="switch">
            <input type="checkbox" @bind="_pushNotifications" />
            <span class="slider"></span>
        </label>
    </div>

    <div class="toggle-row">
        <div>
            <div class="toggle-label">Weekly Digest</div>
            <div class="toggle-desc">Get a summary email every week</div>
        </div>
        <label class="switch">
            <input type="checkbox" @bind="_weeklyDigest" />
            <span class="slider"></span>
        </label>
    </div>

    <div class="channels-section">
        <h4>Muted Channels</h4>
        <p class="channels-desc">Uncheck channels you want to receive notifications from</p>
        <div class="channel-list">
            @foreach (var channel in _channels)
            {
                <label class="channel-item">
                    <input type="checkbox" checked="@channel.Muted"
                           @onchange="e => ToggleChannel(channel.Name, (bool)(e.Value ?? false))" />
                    <span>#@channel.Name</span>
                </label>
            }
        </div>
    </div>

    <div class="button-row">
        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </div>
}

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private class ChannelState
    {
        public string Name { get; set; } = "";
        public bool Muted { get; set; }
    }

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels
            .Select(c => new ChannelState { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private void ToggleChannel(string name, bool muted)
    {
        var ch = _channels.FirstOrDefault(c => c.Name == name);
        if (ch is not null) ch.Muted = muted;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _toastMessage = "Notification preferences saved!";
        _saving = false;
    }
}

.channels-section {
    margin-top: 1.5rem;
}

.channels-section h4 {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.channels-desc {
    font-size: 0.85rem;
    color: #6c757d;
    margin-bottom: 0.75rem;
}

.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    max-width: 450px;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0.6rem;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.9rem;
}

.channel-item:hover {
    background: #f8f9fa;
}

.channel-item input[type="checkbox"] {
    width: 16px;
    height: 16px;
    accent-color: #0d6efd;
}

