@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Security</h2>
    <p>Manage your account security</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message @(_toastIsError ? "toast-error" : "toast-success")">
        @_toastMessage
    </div>
}

@if (_loading)
{
    <p>Loading security settings…</p>
}
else
{
    <!-- Change Password Panel -->
    <div class="expandable-panel">
        <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
            <span>🔑 Change Password</span>
            <span class="chevron @(_passwordPanelOpen ? "open" : "")">▶</span>
        </button>
        @if (_passwordPanelOpen)
        {
            <div class="panel-body">
                <div class="form-group">
                    <label for="currentPassword">Current Password</label>
                    <input id="currentPassword" type="password" @bind="_currentPassword" />
                </div>
                <div class="form-group">
                    <label for="newPassword">New Password</label>
                    <input id="newPassword" type="password" @bind="_newPassword" />
                </div>
                <div class="form-group">
                    <label for="confirmPassword">Confirm New Password</label>
                    <input id="confirmPassword" type="password" @bind="_confirmPassword" />
                </div>
                @if (_passwordError is not null)
                {
                    <div class="field-error">@_passwordError</div>
                }
                <button class="btn btn-primary btn-sm" @onclick="ChangePasswordAsync" disabled="@_changingPassword">
                    @(_changingPassword ? "Updating…" : "Update Password")
                </button>
            </div>
        }
    </div>

    <!-- Two-Factor Authentication -->
    <div class="toggle-row" style="margin-top: 1rem;">
        <div>
            <div class="toggle-label">Two-Factor Authentication</div>
            <div class="toggle-desc">
                @if (_twoFactorEnabled)
                {
                    <span class="status-badge status-on">● Enabled</span>
                }
                else
                {
                    <span class="status-badge status-off">● Disabled</span>
                }
            </div>
        </div>
        <label class="switch">
            <input type="checkbox" @bind="_twoFactorEnabled" />
            <span class="slider"></span>
        </label>
    </div>

    @if (_lastPasswordChange.HasValue)
    {
        <p class="last-changed">Last password change: @_lastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
    }

    <!-- Active Sessions -->
    <div class="sessions-section">
        <h4>Active Sessions</h4>
        <div class="sessions-table-wrapper">
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-danger btn-sm"
                                            @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="current-badge">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>

    <!-- Revoke Confirmation Dialog -->
    @if (_revokeTarget is not null)
    {
        <div class="modal-overlay" @onclick="CancelRevoke">
            <div class="modal-dialog" @onclick:stopPropagation="true">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@_revokeTarget.Device</strong> in @_revokeTarget.Location?</p>
                <div class="button-row">
                    <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                    <button class="btn btn-outline" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
}

@code {
    private bool _loading = true;
    private bool _passwordPanelOpen;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];
    private string _currentSessionId = "sess-1";

    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _changingPassword;

    private string? _toastMessage;
    private bool _toastIsError;

    private ActiveSession? _revokeTarget;

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions.ToList();
        _loading = false;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 8)
        {
            _passwordError = "New password must be at least 8 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _toastMessage = "Password updated successfully!";
            _toastIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            _lastPasswordChange = DateTime.UtcNow;
        }
        catch (Exception)
        {
            _toastMessage = "Failed to change password.";
            _toastIsError = true;
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void PromptRevoke(ActiveSession session)
    {
        _revokeTarget = session;
    }

    private void CancelRevoke()
    {
        _revokeTarget = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_revokeTarget is null) return;
        await SettingsService.RevokeSessionAsync(_revokeTarget.Id);
        _sessions.RemoveAll(s => s.Id == _revokeTarget.Id);
        _toastMessage = $"Session on {_revokeTarget.Device} revoked.";
        _toastIsError = false;
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

