arguments.file_text:
@inject ISettingsService SettingsService

<div class="section-header">
    <h2>Appearance</h2>
    <p>Customize how the application looks</p>
</div>

@if (_toastMessage is not null)
{
    <div class="toast-message toast-success">@_toastMessage</div>
}

@if (_loading)
{
    <p>Loading appearance settings…</p>
}
else
{
    <div class="appearance-layout">
        <div class="appearance-form">
            <!-- Theme -->
            <fieldset class="option-group">
                <legend>Theme</legend>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-card @(_theme == theme ? "selected" : "")">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Font Size -->
            <fieldset class="option-group">
                <legend>Font Size</legend>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-card @(_fontSize == size ? "selected" : "")">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </fieldset>

            <!-- Language -->
            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="toggle-row">
                <div>
                    <div class="toggle-label">Compact Mode</div>
                    <div class="toggle-desc">Reduce spacing for denser layouts</div>
                </div>
                <label class="switch">
                    <input type="checkbox" @bind="_compactMode" />
                    <span class="slider"></span>
                </label>
            </div>

            <div class="button-row">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>
        </div>

        <!-- Live Preview -->
        <div class="preview-panel">
            <h4>Preview</h4>
            <div class="preview-window @GetPreviewClasses()">
                <div class="preview-header">
                    <div class="preview-dot red"></div>
                    <div class="preview-dot yellow"></div>
                    <div class="preview-dot green"></div>
                    <span class="preview-title">My Application</span>
                </div>
                <div class="preview-body">
                    <div class="preview-nav">
                        <div class="preview-nav-item active">Dashboard</div>
                        <div class="preview-nav-item">Settings</div>
                    </div>
                    <div class="preview-content">
                        <p class="preview-text">This is how your content will look with the selected settings.</p>
                        <div class="preview-btn">Action Button</div>
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _toastMessage = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _toastMessage = "Appearance settings saved!";
        _saving = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            _ => "preview-light"
        });
        classes.Add(_fontSize.ToLowerInvariant() switch
        {
            "small" => "preview-font-sm",
            "large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(' ', classes);
    }
}

.appearance-layout {
    display: flex;
    gap: 2.5rem;
}

.appearance-form {
    flex: 1;
    max-width: 450px;
}

.option-group {
    border: none;
    padding: 0;
    margin: 0 0 1.25rem;
}

.option-group legend {
    font-weight: 500;
    font-size: 0.9rem;
    color: #333;
    margin-bottom: 0.5rem;
}

.radio-group {
    display: flex;
    gap: 0.5rem;
}

.radio-card {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.5rem 1rem;
    border: 2px solid #dee2e6;
    border-radius: 8px;
    cursor: pointer;
    font-size: 0.9rem;
    transition: border-color 0.15s, background 0.15s;
}

.radio-card:hover {
    border-color: #adb5bd;
}

.radio-card.selected {
    border-color: #0d6efd;
    background: #e7f1ff;
}

.radio-card input[type="radio"] {
    accent-color: #0d6efd;
}

/* Live Preview */
.preview-panel {
    min-width: 280px;
}

.preview-panel h4 {
    font-size: 1rem;
    font-weight: 600;
    margin-bottom: 0.75rem;
}

.preview-window {
    border: 1px solid #dee2e6;
    border-radius: 10px;
    overflow: hidden;
    transition: all 0.3s;
}

.preview-header {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 0.75rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-dot {
    width: 10px;
    height: 10px;
    border-radius: 50%;
}

.preview-dot.red { background: #ff5f57; }
.preview-dot.yellow { background: #ffbd2e; }
.preview-dot.green { background: #28c840; }

.preview-title {
    margin-left: 0.5rem;
    font-weight: 600;
    font-size: 0.8rem;
}

.preview-body {
    display: flex;
    min-height: 160px;
}

.preview-nav {
    width: 90px;
    border-right: 1px solid;
    padding: 0.5rem 0;
}

.preview-nav-item {
    padding: 0.3rem 0.6rem;
    font-size: 0.72rem;
    cursor: default;
}

.preview-nav-item.active {
    font-weight: 600;
}

.preview-content {
    flex: 1;
    padding: 0.75rem;
}

.preview-text {
    font-size: 0.78rem;
    line-height: 1.4;
    margin-bottom: 0.75rem;
}

.preview-btn {
    display: inline-block;
    padding: 0.25rem 0.7rem;
    border-radius: 4px;
    font-size: 0.72rem;
    font-weight: 500;
}

/* Light theme preview */
.preview-light {
    background: #fff;
    color: #333;
}

.preview-light .preview-header {
    background: #f8f9fa;
    border-color: #dee2e6;
}

.preview-light .preview-nav {
    background: #f8f9fa;
    border-color: #dee2e6;
}

.preview-light .preview-nav-item.active {
    color: #0d6efd;
}

.preview-light .preview-btn {
    background: #0d6efd;
    color: #fff;
}

/* Dark theme preview */
.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #313244;
}

.preview-dark .preview-nav {
    background: #181825;
    border-color: #313244;
}

.preview-dark .preview-nav-item.active {
    color: #89b4fa;
}

.preview-dark .preview-btn {
    background: #89b4fa;
    color: #1e1e2e;
}

/* Font size variants */
.preview-font-sm .preview-text { font-size: 0.68rem; }
.preview-font-md .preview-text { font-size: 0.78rem; }
.preview-font-lg .preview-text { font-size: 0.9rem; }

.preview-font-sm .preview-nav-item { font-size: 0.65rem; }
.preview-font-lg .preview-nav-item { font-size: 0.82rem; }

/* Compact mode */
.preview-compact .preview-body { min-height: 120px; }
.preview-compact .preview-content { padding: 0.4rem; }
.preview-compact .preview-nav-item { padding: 0.15rem 0.4rem; }

